import SHOP_DATA from "./shop.data";
const INITIAL_STATE = {
    collection: SHOP_DATA
};

const collectionReducer = (state=INITIAL_STATE, action) => {
    switch (action.type) {
        default:
            return state;
    }
};

export default collectionReducer;
